import React, { useEffect } from 'react';
import clsx from 'clsx';
import { makeStyles } from '@material-ui/core/styles';
import Drawer from '@material-ui/core/Drawer';
import Button from '@material-ui/core/Button';
import List from '@material-ui/core/List';
import Divider from '@material-ui/core/Divider';
import ListItem from '@material-ui/core/ListItem';
import ListItemIcon from '@material-ui/core/ListItemIcon';
import ListItemText from '@material-ui/core/ListItemText';
import MenuIcon from '@material-ui/icons/Menu';
import { useDispatch, useSelector } from 'react-redux';
import { getPlayers } from '../../actions/players';
import { useNavigate } from 'react-router-dom';

const useStyles = makeStyles({
    list: {
      width: 250,
    },
    fullList: {
      width: 'auto',
    },
    menuIcon: {
      color: 'white',
    },
  });
  
  export default function TemporaryDrawer() {
    const classes = useStyles();
    const dispatch = useDispatch();
    const history = useNavigate();
    const categories = useSelector((state) => state.menus);
  
    const [state, setState] = React.useState({
      top: false,
    });
  
    const toggleDrawer = (anchor, open) => (event) => {
      if (event.type === 'keydown' && (event.key === 'Tab' || event.key === 'Shift')) {
        return;
      }
  
      setState({ ...state, [anchor]: open });
    };
  
    useEffect(() => {
      console.log("categories: ", categories);
    }, [categories]);
  
    const listPlayers = (e, mainMenu, sub) => {
      e.preventDefault();
      const selectedCategories = [mainMenu, sub];
      dispatch(getPlayers({ name: selectedCategories.join(',') }));
      history(`/players/search?searchQuery=${selectedCategories.join(',')}`, { redirect: true });
    };
  
    const generateMenuItems = () => {
      return categories.map((mainMenu) => (
        <div key={mainMenu.mainMenu}>
          <List>
            <ListItem button>
              <ListItemIcon>{/* Add your icon component here */}</ListItemIcon>
              <ListItemText primary={mainMenu.mainMenu} />
            </ListItem>
          </List>
          <Divider />
          <List>
            {mainMenu.subMenus.map((sub) => (
              <ListItem button key={sub} onClick={(e) => listPlayers(e, mainMenu.mainMenu, sub)}>
                <ListItemIcon>{/* Add your icon component here */}</ListItemIcon>
                <ListItemText primary={sub} />
              </ListItem>
            ))}
          </List>
        </div>
      ));
    };
  
    return (
      <div>
        <Button onClick={toggleDrawer('top', true)}>
          <MenuIcon className={classes.menuIcon} />
        </Button>
        <Drawer anchor="top" open={state['top']} onClose={toggleDrawer('top', false)}>
          {generateMenuItems()}
        </Drawer>
      </div>
    );
  }
